class Solution {
public:
bool solve(int n, int m, int* coins, int* dp)
{
	memset(dp, 0, sizeof(dp));
	// Base case: if m is 0, we need 0 coins
	if (m == 0) return true;
	// If m is negative, it's impossible to reach the target
	if (m < 0) return false;
	// For each coin, check if we can reach the target
	for (int coin = 0; coin < n; ++coin)
	{
		for (int i = coins[coin]; i <= m; ++i)
		    if (!dp[i])
		    {
				// If we can reach the target by including the current coin, mark it as true
				dp[i] = true;
				break;
			}
		}
	return dp[m];
}
};

